package com.maum.backend.call.domain

enum class CallStatus {
    PENDING,    // 통화 요청 대기 중
    RINGING,    // 상대방 수신 중
    ACTIVE,     // 통화 진행 중
    ENDED,      // 통화 종료
    MISSED,     // 부재중
    REJECTED    // 거절됨
}
```

