### `CallEntity.kt`

```kotlin
package com.maum.backend.call.domain

import java.time.Instant

data class CallEntity(
    val id: String,
    val callerId: String,
    val receiverId: String,
    var status: CallStatus = CallStatus.PENDING,
    val startedAt: Instant = Instant.now(),
    var endedAt: Instant? = null,
    var durationSeconds: Long? = null
) {
    fun isActive(): Boolean = status == CallStatus.ACTIVE

    fun canBeAnswered(): Boolean = status == CallStatus.RINGING

    fun canBeRejected(): Boolean = status == CallStatus.RINGING || status == CallStatus.PENDING

    fun end(endTime: Instant = Instant.now()) {
        require(status == CallStatus.ACTIVE) {
            "ACTIVE 상태의 통화만 종료할 수 있습니다. 현재 상태: $status"
        }
        status = CallStatus.ENDED
        endedAt = endTime
        durationSeconds = endTime.epochSecond - startedAt.epochSecond
    }
}
```

