package com.maum.backend.call.exception

class CallNotFoundException(callId: String) :
    RuntimeException("통화를 찾을 수 없습니다: $callId")

class CallAlreadyActiveException(userId: String) :
    RuntimeException("이미 진행 중인 통화가 있습니다: $userId")

class CallNotAnswerableException(callId: String, currentStatus: String) :
    RuntimeException("수신할 수 없는 통화입니다. callId=$callId, 현재 상태=$currentStatus")

class UnauthorizedCallAccessException(userId: String, callId: String) :
    RuntimeException("해당 통화에 접근 권한이 없습니다. userId=$userId, callId=$callId")

class SelfCallException(userId: String) :
    RuntimeException("자기 자신에게 통화를 걸 수 없습니다: $userId")
```

