### `CallServiceTest.kt` (TDD Red-Green-Refactor)

```kotlin
package com.maum.backend.call.service

import com.maum.backend.call.domain.CallEntity
import com.maum.backend.call.domain.CallStatus
import com.maum.backend.call.exception.*
import com.maum.backend.call.repository.CallRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.`when`
import org.mockito.Mockito.verify
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import java.time.Instant
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class CallServiceTest {

    @Mock
    private lateinit var callRepository: CallRepository

    @InjectMocks
    private lateinit var callService: CallService

    // ===== initiateCall =====

    @Test
    fun `should initiate call successfully when both users are available`() {
        // given
        val callerId = "user-A"
        val receiverId = "user-B"
        val expectedCall = buildCall(callerId = callerId, receiverId = receiverId, status = CallStatus.RINGING)

        `when`(callRepository.findActiveCallByUserId(callerId)).thenReturn(Optional.empty())
        `when`(callRepository.findActiveCallByUserId(receiverId)).thenReturn(Optional.empty())
        `when`(callRepository.save(any())).thenReturn(expectedCall)

        // when
        val result = callService.initiateCall(callerId, receiverId)

        // then
        assertThat(result.callerId).isEqualTo(callerId)
        assertThat(result.receiverId).isEqualTo(receiverId)
        assertThat(result.status).isEqualTo(CallStatus.RINGING)
        verify(callRepository).save(any())
    }

    @Test
    fun `should throw SelfCallException when caller and receiver are the same`() {
        // given
        val userId = "user-A"

        // when & then
        assertThrows<SelfCallException> {
            callService.initiateCall(userId, userId)
        }
    }

    @Test
    fun `should throw CallAlreadyActiveException when caller is already in a call`() {
        // given
        val callerId = "user-A"
        val activeCall = buildCall(callerId = callerId, receiverId = "user-C", status = CallStatus.ACTIVE)
        `when`(callRepository.findActiveCallByUserId(callerId)).thenReturn(Optional.of(activeCall))

        // when & then
        assertThrows<CallAlreadyActiveException> {
            callService.initiateCall(callerId, "user-B")
        }
    }

    @Test
    fun `should throw CallAlreadyActiveException when receiver is already in a call`() {
        // given
        val receiverId = "user-B"
        val activeCall = buildCall(callerId = "user-C", receiverId = receiverId, status = CallStatus.ACTIVE)
        `when`(callRepository.findActiveCallByUserId("user-A")).thenReturn(Optional.empty())
        `when`(callRepository.findActiveCallByUserId(receiverId)).thenReturn(Optional.of(activeCall))

        // when & then
        assertThrows<CallAlreadyActiveException> {
            callService.initiateCall("user-A", receiverId)
        }
    }

    // ===== answerCall =====

    @Test
    fun `should answer call successfully when call is RINGING and user is receiver`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val ringingCall = buildCall(callId = callId, callerId = "user-A", receiverId = receiverId, status = CallStatus.RINGING)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(ringingCall))
        `when`(callRepository.save(any())).thenAnswer { it.arguments[0] }

        // when
        val result = callService.answerCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ACTIVE)
    }

    @Test
    fun `should throw CallNotFoundException when answering non-existent call`() {
        // given
        `when`(callRepository.findById("no-call")).thenReturn(Optional.empty())

        // when & then
        assertThrows<CallNotFoundException> {
            callService.answerCall("no-call", "user-B")
        }
    }

    @Test
    fun `should throw UnauthorizedCallAccessException when non-receiver tries to answer`() {
        // given
        val callId = "call-1"
        val ringingCall = buildCall(callId = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.RINGING)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(ringingCall))

        // when & then
        val ex = assertThrows<UnauthorizedCallAccessException> {
            callService.answerCall(callId, "user-C")
        }
        assertThat(ex.message).contains("user-C")
    }

    @Test
    fun `should throw CallNotAnswerableException when answering an ACTIVE call`() {
        // given
        val callId = "call-1"
        val activeCall = buildCall(callId = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.ACTIVE)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))

        // when & then
        assertThrows<CallNotAnswerableException> {
            callService.answerCall(callId, "user-B")
        }
    }

    @Test
    fun `should throw CallNotAnswerableException when answering an ENDED call`() {
        // given
        val callId = "call-1"
        val endedCall = buildCall(callId = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.ENDED)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(endedCall))

        // when & then
        assertThrows<CallNotAnswerableException> {
            callService.answerCall(callId, "user-B")
        }
    }

    // ===== rejectCall =====

    @Test
    fun `should reject call successfully when call is RINGING and user is receiver`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val ringingCall = buildCall(callId = callId, callerId = "user-A", receiverId = receiverId, status = CallStatus.RINGING)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(ringingCall))
        `when`(callRepository.save(any())).thenAnswer { it.arguments[0] }

        // when
        val result = callService.rejectCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.REJECTED)
    }

    @Test
    fun `should throw UnauthorizedCallAccessException when caller tries to reject own outgoing call`() {
        // given - 버그 재현: 발신자가 자신의 통화를 거절하려는 시도
        val callId = "call-1"
        val callerId = "user-A"
        val ringingCall = buildCall(callId = callId, callerId = callerId, receiverId = "user-B", status = CallStatus.RINGING)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(ringingCall))

        // when & then
        assertThrows<UnauthorizedCallAccessException> {
            callService.rejectCall(callId, callerId)
        }
    }

    // ===== endCall =====

    @Test
    fun `should end call successfully when caller ends ACTIVE call`() {
        // given
        val callId = "call-1"
        val callerId = "user-A"
        val startTime = Instant.now().minusSeconds(120)
        val activeCall = buildCall(callId = callId, callerId = callerId, receiverId = "user-B", status = CallStatus.ACTIVE, startedAt = startTime)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))
        `when`(callRepository.save(any())).thenAnswer { it.arguments[0] }

        // when
        val result = callService.endCall(callId, callerId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ENDED)
        assertThat(result.endedAt).isNotNull
        assertThat(result.durationSeconds).isGreaterThanOrEqualTo(120L)
    }

    @Test
    fun `should end call successfully when receiver ends ACTIVE call`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val activeCall = buildCall(callId = callId, callerId = "user-A", receiverId = receiverId, status = CallStatus.ACTIVE)

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))
        `when`(callRepository.save(any())).thenAnswer { it.arguments[0] }

        // when
        val result = callService.endCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ENDED)
    }

    @Test
    fun `should throw UnauthorizedCallAccessException when unrelated user tries to end call`() {
        // given
        val callId = "call-1"
        val activeCall = buildCall(callId = callId, callerId = "user-A", receiverId = "user-B", status = CallStatus.ACTIVE)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))

        // when & then
        assertThrows<UnauthorizedCallAccessException> {
            callService.endCall(callId, "user-C")
        }
    }

    @Test
    fun `should throw IllegalArgumentException when ending a RINGING call`() {
        // given - 버그 재현: RINGING 상태의 통화에 end() 호출 시 상태 검증 누락 버그
        val callId = "call-1"
        val callerId = "user-A"
        val ringingCall = buildCall(callId = callId, callerId = callerId, receiverId = "user-B", status = CallStatus.RINGING)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(ringingCall))

        // when & then
        assertThrows<IllegalArgumentException> {
            callService.endCall(callId, callerId)
        }
    }

    @Test
    fun `should throw IllegalArgumentException when ending an already ENDED call`() {
        // given - 버그 재현: 이미 종료된 통화를 중복으로 종료하려는 시도
        val callId = "call-1"
        val callerId = "user-A"
        val endedCall = buildCall(callId = callId, callerId = callerId, receiverId = "user-B", status = CallStatus.ENDED)
        `when`(callRepository.findById(callId)).thenReturn(Optional.of(endedCall))

        // when & then
        assertThrows<IllegalArgumentException> {
            callService.endCall(callId, callerId)
        }
    }

    // ===== getCallHistory =====

    @Test
    fun `should return call history for user`() {
        // given
        val userId = "user-A"
        val calls = listOf(
            buildCall(callerId = userId, receiverId = "user-B", status = CallStatus.ENDED),
            buildCall(callerId = "user-C", receiverId = userId, status = CallStatus.ENDED)
        )
        `when`(callRepository.findByCallerIdOrReceiverId(userId, userId)).thenReturn(calls)

        // when
        val result = callService.getCallHistory(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.all { it.callerId == userId || it.receiverId == userId }).isTrue
    }

    @Test
    fun `should return empty list when user has no call history`() {
        // given
        val userId = "new-user"
        `when`(callRepository.findByCallerIdOrReceiverId(userId, userId)).thenReturn(emptyList())

        // when
        val result = callService.getCallHistory(userId)

        // then
        assertThat(result).isEmpty()
    }

    // ===== CallEntity 도메인 단위 테스트 =====

    @Test
    fun `should calculate duration correctly when call ends`() {
        // given
        val startTime = Instant.parse("2024-01-01T10:00:00Z")
        val endTime = Instant.parse("2024-01-01T10:05:00Z")
        val call = buildCall(status = CallStatus.ACTIVE, startedAt = startTime)

        // when
        call.end(endTime)

        // then
        assertThat(call.status).isEqualTo(CallStatus.ENDED)
        assertThat(call.durationSeconds).isEqualTo(300L)
        assertThat(call.endedAt).isEqualTo(endTime)
    }

    @Test
    fun `should return true for isActive when status is ACTIVE`() {
        val call = buildCall(status = CallStatus.ACTIVE)
        assertThat(call.isActive()).isTrue
    }

    @Test
    fun `should return false for isActive when status is not ACTIVE`() {
        assertThat(buildCall(status = CallStatus.PENDING).isActive()).isFalse
        assertThat(buildCall(status = CallStatus.RINGING).isActive()).isFalse
        assertThat(buildCall(status = CallStatus.ENDED).isActive()).isFalse
        assertThat(buildCall(status = CallStatus.REJECTED).isActive()).isFalse
    }

    // ===== 헬퍼 =====

    private fun buildCall(
        callId: String = "call-id",
        callerId: String = "caller-id",
        receiverId: String = "receiver-id",
        status: CallStatus = CallStatus.RINGING,
        startedAt: Instant = Instant.now()
    ): CallEntity = CallEntity(
        id = callId,
        callerId = callerId,
        receiverId = receiverId,
        status = status,
        startedAt = startedAt
    )
}
```

