### `CallService.kt`

```kotlin
package com.maum.backend.call.service

import com.maum.backend.call.domain.CallEntity
import com.maum.backend.call.domain.CallStatus
import com.maum.backend.call.exception.*
import com.maum.backend.call.repository.CallRepository
import java.util.UUID

class CallService(
    private val callRepository: CallRepository
) {

    /** 통화 시작 요청 */
    fun initiateCall(callerId: String, receiverId: String): CallEntity {
        if (callerId == receiverId) {
            throw SelfCallException(callerId)
        }
        callRepository.findActiveCallByUserId(callerId).ifPresent {
            throw CallAlreadyActiveException(callerId)
        }
        callRepository.findActiveCallByUserId(receiverId).ifPresent {
            throw CallAlreadyActiveException(receiverId)
        }
        val call = CallEntity(
            id = UUID.randomUUID().toString(),
            callerId = callerId,
            receiverId = receiverId,
            status = CallStatus.RINGING
        )
        return callRepository.save(call)
    }

    /** 통화 수락 (수신자만 가능, RINGING 상태만) */
    fun answerCall(callId: String, userId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { CallNotFoundException(callId) }
        if (call.receiverId != userId) {
            throw UnauthorizedCallAccessException(userId, callId)
        }
        if (!call.canBeAnswered()) {
            throw CallNotAnswerableException(callId, call.status.name)
        }
        call.status = CallStatus.ACTIVE
        return callRepository.save(call)
    }

    /** 통화 거절 (수신자만 가능, RINGING/PENDING 상태만) */
    fun rejectCall(callId: String, userId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { CallNotFoundException(callId) }
        if (call.receiverId != userId) {
            throw UnauthorizedCallAccessException(userId, callId)
        }
        if (!call.canBeRejected()) {
            throw CallNotAnswerableException(callId, call.status.name)
        }
        call.status = CallStatus.REJECTED
        return callRepository.save(call)
    }

    /** 통화 종료 (발신자 또는 수신자 가능, ACTIVE 상태만) */
    fun endCall(callId: String, userId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { CallNotFoundException(callId) }
        if (call.callerId != userId && call.receiverId != userId) {
            throw UnauthorizedCallAccessException(userId, callId)
        }
        call.end()
        return callRepository.save(call)
    }

    /** 통화 이력 조회 */
    fun getCallHistory(userId: String): List<CallEntity> =
        callRepository.findByCallerIdOrReceiverId(userId, userId)
}
